INSERT INTO plants (plantname, price, category, humidity, temperature, description, size) VALUES
('گل رز', 120000, 'پیشنهادی', 50, '۱۸ تا ۲۵ درجه', 'گل رز یکی از محبوب‌ترین گل‌های زینتی است؛ با رنگ‌های متنوع و رایحه خوش برای هدیه و تزئین فضای خانه و باغچه بسیار مناسب است. آبیاری منظم و نور غیرمستقیم نیاز دارد.', 'متوسط'),
('سنبل', 85000, 'آپارتمانی', 60, '۱۵ تا ۲۲ درجه', 'سنبل گیاهی معطر و زیبا با گل‌های خوشه‌ای است که برای فضای بسته و آپارتمان ایده‌آل است. در بهار گل می‌دهد و با نگهداری ساده می‌تواند سال‌ها در گلدان بماند.', 'کوچک'),
('کاکتوس', 65000, 'محل‌کار', 30, '۲۰ تا ۲۸ درجه', 'کاکتوس گیاهی بسیار مقاوم و کم‌نیاز است؛ به آبیاری کم و نور معمولی اتاق عادت دارد و برای میز کار و محیط اداری گزینه مناسبی است. در اندازه‌های مختلف موجود است.', 'کوچک'),
('شمعدانی', 95000, 'باغچه‌ای', 55, '۱۰ تا ۲۵ درجه', 'شمعدانی با گل‌های رنگارنگ قرمز، صورتی و سفید یکی از بهترین گزینه‌ها برای باغچه و فضای باز است. نور زیاد و آبیاری منظم را دوست دارد و در فصول گرم به خوبی گل می‌دهد.', 'متوسط'),
('دیفن باخیا', 110000, 'سمی', 70, '۱۸ تا ۲۴ درجه', 'دیفن باخیا گیاه آپارتمانی با برگ‌های پهن و رگه‌دار است. توجه کنید که شیره و برگ‌های آن سمی هستند و باید از دسترس کودکان و حیوانات دور نگه داشته شود. به رطوبت و نور غیرمستقیم نیاز دارد.', 'متوسط'),
('پتوس', 70000, 'آپارتمانی', 65, '۱۷ تا ۲۶ درجه', 'پتوس گیاهی رونده و بسیار مقاوم است؛ در نور کم هم رشد می‌کند و به تصفیه هوا کمک می‌کند. برای گلدان آویز یا روی قفسه مناسب است و نگهداری آن برای تازه‌کارها هم آسان است.', 'متوسط'),
('گل داوودی', 135000, 'پیشنهادی', 50, '۱۵ تا ۲۰ درجه', 'گل داوودی در رنگ‌های سفید، زرد، بنفش و قرمز برای فضای باز و باغچه عالی است. گل‌دهی پاییزه دارد و با هرس به موقع می‌توان چند سال از آن استفاده کرد.', 'متوسط'),
('نخل اریکا', 180000, 'محل‌کار', 60, '۱۸ تا ۲۷ درجه', 'نخل اریکا نخل زینتی با برگ‌های سبز و ظریف است و برای محیط اداری و پذیرایی مناسب است. به نور غیرمستقیم و رطوبت متوسط نیاز دارد و در فضای بسته به خوبی رشد می‌کند.', 'بزرگ'),
('بگونیا', 78000, 'باغچه‌ای', 55, '۱۶ تا ۲۴ درجه', 'بگونیا با برگ‌ها و گل‌های رنگی برای گلدان و باغچه مناسب است. گونه‌های مختلفی دارد؛ بعضی برای گل و بعضی برای برگ‌های زینتی نگهداری می‌شوند. آبیاری منظم و نور فیلتر شده لازم دارد.', 'کوچک'),
('آلوئه ورا', 90000, 'پیشنهادی', 40, '۲۰ تا ۲۵ درجه', 'آلوئه ورا گیاهی دارویی و مفید برای پوست و سوختگی است؛ ژل داخل برگ آن در مصارف خانگی و آرایشی استفاده می‌شود. کم‌آب و نور زیاد را دوست دارد و نگهداری آن ساده است.', 'متوسط');
